import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom"; // ✅ navegación React
import "../styles/registro.css";

function Registro() {
  const navigate = useNavigate(); // ✅ para redireccionar

  const [nombre, setNombre] = useState("");
  const [tipo, setTipo] = useState("");
  const [documento, setDocumento] = useState("");
  const [telefono, setTelefono] = useState("");
  const [password, setPassword] = useState("");
  const [showDoc, setShowDoc] = useState(false);
  const [showPass, setShowPass] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();

    // Simulación de envío
    console.log({
      nombre,
      tipo,
      documento,
      telefono,
      password,
    });

    // ✅ Redirigir al login (React Router)
    navigate("/login");
  };

  return (
    <div className="form-container">
      <h2 className="titulo">Registro</h2>

      <form onSubmit={handleSubmit}>
        <label>Nombre completo</label>
        <div className="input-box">
          <input
            type="text"
            placeholder="Nombre completo"
            value={nombre}
            onChange={(e) => setNombre(e.target.value)}
            required
          />
        </div>

        <label>Tipo de documento</label>
        <div className="input-box">
          <select
            value={tipo}
            onChange={(e) => setTipo(e.target.value)}
            required
          >
            <option value="">Seleccione documento</option>
            <option value="cc">Cédula de ciudadanía</option>
            <option value="ti">Tarjeta de identidad</option>
            <option value="ce">Cédula de extranjería</option>
          </select>
        </div>

        <label>Número de documento</label>
        <div className="input-box">
          <input
            type={showDoc ? "text" : "password"}
            placeholder="••••••••••"
            value={documento}
            onChange={(e) => setDocumento(e.target.value)}
            required
          />
          <span
            className="eye"
            onClick={() => setShowDoc(!showDoc)}
            style={{ cursor: "pointer" }}
          >
            {showDoc ? "🙈" : "👁️"}
          </span>
        </div>

        <label>Número teléfono</label>
        <div className="input-box">
          <input
            type="tel"
            placeholder="XXXXXXXX"
            value={telefono}
            onChange={(e) => setTelefono(e.target.value)}
            required
          />
        </div>

        <label>Contraseña</label>
        <div className="input-box">
          <input
            type={showPass ? "text" : "password"}
            placeholder="••••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />
          <span
            className="eye"
            onClick={() => setShowPass(!showPass)}
            style={{ cursor: "pointer" }}
          >
            {showPass ? "🙈" : "👁️"}
          </span>
        </div>

        <button type="submit" className="btn">
          Acceso
        </button>

        <p className="texto-sec">
          ¿Ya tienes una cuenta?{" "}
          <Link to="/login">Inicia sesión aquí</Link>
        </p>

        <p className="texto-info">
          Términos de servicio y la Política de privacidad.
        </p>
      </form>
    </div>
  );
}

export default Registro;
